import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  const user = JSON.parse(localStorage.getItem("user"));
  const role = user?.role;

  const [showModal, setShowModal] = useState(false);

  const [passwordData, setPasswordData] = useState({
    oldPassword: "",
    newPassword: "",
  });

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/");
  };

  const handlePasswordChange = (e) => {
    setPasswordData({
      ...passwordData,
      [e.target.name]: e.target.value,
    });
  };

  const handleUpdatePassword = () => {
    console.log(passwordData);
    setShowModal(false);
  };

  return (
    <>
      {/* Navbar */}
      <div className="bg-indigo-600 text-white px-6 py-4 flex justify-between items-center shadow-md">

        {/* Left */}
        <h1 className="text-xl font-bold">Roxiler</h1>

        {/* Right */}
        <div className="flex items-center gap-6 text-sm font-medium">

          {/* ADMIN */}
          {role === "admin" && (
            <>
              <Link to="/home">Home</Link>
              <Link to="/users">Users</Link>
              <Link to="/stores">Stores</Link>
            </>
          )}

          {/* USER */}
          {role === "user" && (
            <>
                <Link to="/home">Home</Link>
                <Link to="/dashboard">Stores</Link>
            </>
          )}

          {/* STORE OWNER */}
          {role === "store_owner" && (
            <>
              <Link to="/store-dashboard">Home</Link>
              <Link to="/your-stores">Your Stores</Link>
            </>
          )}

          {/* COMMON */}
          {(role === "store_owner" || role === "user") && (
            <button
              onClick={() => setShowModal(true)}   
            >
              Update Password
            </button>
          )}

          <button
            onClick={handleLogout}
            className="bg-red-500 px-3 py-1 rounded hover:bg-red-600"
          >
            Logout
          </button>

        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex justify-center items-center z-50">

          <div className="bg-white p-6 rounded-lg w-[320px] shadow-lg">

            <h3 className="text-lg font-bold mb-4">Update Password</h3>

            <input
              type="password"
              name="oldPassword"
              placeholder="Old Password"
              value={passwordData.oldPassword}
              onChange={handlePasswordChange}
              className="w-full mb-3 px-3 py-2 border rounded"
            />

            <input
              type="password"
              name="newPassword"
              placeholder="New Password"
              value={passwordData.newPassword}
              onChange={handlePasswordChange}
              className="w-full mb-4 px-3 py-2 border rounded"
            />

            <div className="flex justify-between">
              <button
                onClick={() => setShowModal(false)}
                className="bg-gray-300 px-3 py-1 rounded"
              >
                Cancel
              </button>

              <button
                onClick={handleUpdatePassword}
                className="bg-indigo-600 text-white px-3 py-1 rounded"
              >
                Update
              </button>
            </div>

          </div>
        </div>
      )}
    </>
  );
}

export default Navbar;
